module RefModule(
    input clk,
    input reset,
    input enable,
    output reg [11:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset) begin
            // Synchronous reset: Reset the counter to 12'b000000000000
            q <= 12'b000000000000;
        end else if (enable) begin
            // Counter increment: Increment by 1 when enabled
            q <= q + 1;
        end
    end

endmodule
